const input = $input.first().json;
const projectId = $('Generate Rubric Prompt').first().json.projectId;

let rubricText = input.output || input.text || '';
rubricText = rubricText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let rubricItems = [];
try {
  rubricItems = JSON.parse(rubricText);
} catch (e) {
  return [{
    json: {
      error: 'Failed to parse rubric JSON',
      raw: rubricText,
      projectId
    }
  }];
}

// Normalize weights so they always sum to exactly 1.0
const totalWeight = rubricItems.reduce((sum, r) => sum + (r.weight || 0), 0);
const multiplier = totalWeight > 0 ? 1 / totalWeight : 1 / rubricItems.length;

const supabaseRows = rubricItems.map((item, index) => ({
  project_id: projectId,
  criterion: item.criterion,
  description: item.description,
  max_score: item.max_score || 10,
  weight: parseFloat(((item.weight || (1 / rubricItems.length)) * multiplier).toFixed(4)),
  scoring_guide: item.scoring_guide || null,
  sort_order: index
}));

return [{
  json: {
    projectId,
    rubricItems: supabaseRows,
    rubricForFrontend: supabaseRows
  }
}];
